async function beBuildPrompt() {
  const items = $input.all();
  if (!items.length) {
    throw new Error('Backend structure prompt builder received no input.');
  }

  async function readBinaryText(itemIndex, propertyName, fallbackFileName) {
    const item = items[itemIndex];
    const binary = item.binary?.[propertyName];
    if (!binary) return null;

    const buffer = await this.helpers.getBinaryDataBuffer(itemIndex, propertyName);
    return {
      fileName: binary.fileName || fallbackFileName,
      text: buffer.toString('utf8'),
    };
  }

  let requirements = null;
  let openapi = null;

  for (let itemIndex = 0; itemIndex < items.length; itemIndex += 1) {
    if (!requirements) {
      requirements = await readBinaryText.call(this, itemIndex, 'requirements', 'requirements-compact.txt');
    }
    if (!openapi) {
      openapi = await readBinaryText.call(this, itemIndex, 'openapiSpec', 'openapi-compact.json');
    }
  }

  if (!requirements) {
    throw new Error('Missing compact requirements binary for backend structure generation.');
  }
  if (!openapi) {
    throw new Error('Missing compact openapiSpec binary for backend structure generation.');
  }

  const requirementsText = String(requirements.text || '').trim();
  const openapiText = String(openapi.text || '').trim();
  if (!requirementsText) {
    throw new Error('Requirements text is empty for backend structure generation.');
  }
  if (!openapiText) {
    throw new Error('OpenAPI text is empty for backend structure generation.');
  }

  const userPrompt = [
    'REQ',
    requirementsText,
    'API',
    openapiText,
  ].join('\n');

  return [{
    json: {
      requirementsFile: requirements.fileName,
      requirementsText,
      requirementsPromptLength: requirementsText.length,
      openapiFile: openapi.fileName || 'openapi-compact.json',
      openapiText,
      openapiPromptLength: openapiText.length,
      userPrompt,
      fullPromptLength: userPrompt.length,
    },
    binary: items[0].binary ?? {},
  }];
}

return await beBuildPrompt.call(this);

function beCleanStructure() {
  function parseJsonCandidate(raw) {
    try {
      const parsed = JSON.parse(raw);
      if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
        return parsed;
      }
    } catch {}
    return null;
  }

  function normalizeText(raw) {
    let text = String(raw ?? '').trim();
    if (!text) {
      throw new Error('Backend structure model output is empty.');
    }

    if (text.startsWith('```')) {
      const firstNewlineIndex = text.indexOf('\n');
      if (firstNewlineIndex !== -1) {
        const openingFence = text.slice(0, firstNewlineIndex).trim();
        if (/^```(?:json)?$/i.test(openingFence)) {
          text = text.slice(firstNewlineIndex + 1);

          const trailingFenceIndex = text.lastIndexOf('\n```');
          if (trailingFenceIndex !== -1 && text.slice(trailingFenceIndex).trim() === '```') {
            text = text.slice(0, trailingFenceIndex).trim();
          } else if (text.endsWith('```')) {
            text = text.slice(0, -3).trim();
          } else {
            text = text.trim();
          }
        }
      }
    }

    return text;
  }

  function extractBalancedObject(text) {
    let depth = 0;
    let start = -1;
    let inString = false;
    let escaped = false;

    for (let index = 0; index < text.length; index += 1) {
      const char = text[index];

      if (escaped) {
        escaped = false;
        continue;
      }

      if (char === '\\') {
        if (inString) escaped = true;
        continue;
      }

      if (char === '"') {
        inString = !inString;
        continue;
      }

      if (inString) continue;

      if (char === '{') {
        if (depth === 0) start = index;
        depth += 1;
        continue;
      }

      if (char === '}') {
        if (depth > 0) {
          depth -= 1;
          if (depth === 0 && start !== -1) {
            return text.slice(start, index + 1);
          }
        }
      }
    }

    return null;
  }

  function extractStructure(rawText) {
    const text = normalizeText(rawText);
    const candidates = [text];
    const balancedObject = extractBalancedObject(text);
    if (balancedObject) {
      candidates.push(balancedObject);
    }

    for (const candidate of candidates) {
      const parsed = parseJsonCandidate(candidate);
      if (parsed) return parsed;
    }

    throw new Error('Could not extract a valid backend structure JSON document from model output.');
  }

  function normalizeFileEntry(file, index) {
    if (typeof file === 'string') {
      const path = file.trim();
      if (!path) {
        throw new Error(`files[${index}] must not be empty.`);
      }
      return { path };
    }

    if (!file || typeof file !== 'object' || Array.isArray(file)) {
      throw new Error(`files[${index}] must be a string path or an object with path.`);
    }

    const filePath = String(file.path || '').trim();
    if (!filePath) {
      throw new Error(`files[${index}].path is required.`);
    }

    return { path: filePath };
  }

  function validateAndNormalizeStructure(payload) {
    if (!payload || typeof payload !== 'object' || Array.isArray(payload)) {
      throw new Error('Backend structure must be an object.');
    }
    if (!Array.isArray(payload.files)) {
      throw new Error('Backend structure must contain a files array.');
    }
    if (!payload.files.length) {
      throw new Error('Backend structure files array must not be empty.');
    }

    const seen = new Set();
    const normalizedFiles = payload.files.map((file, index) => {
      const normalized = normalizeFileEntry(file, index);
      const filePath = normalized.path;
      if (!filePath.startsWith('backend/')) {
        throw new Error(`files[${index}].path must start with "backend/".`);
      }
      if (seen.has(filePath)) {
        throw new Error(`Duplicate backend structure file path: ${filePath}`);
      }
      seen.add(filePath);
      return normalized;
    });

    return { files: normalizedFiles };
  }

  const item = $input.first();
  const structure = validateAndNormalizeStructure(extractStructure(item?.json?.text));

  return [{
    json: {
      ...(item?.json ?? {}),
      backendStructure: JSON.stringify(structure, null, 2),
      backendStructureObject: structure,
      structureFileCount: structure.files.length,
    },
    binary: item?.binary ?? {},
  }];
}
return beCleanStructure();

function beInitGenerationState() {
  const item = $input.first();
  if (!item) {
    throw new Error('No backend structure item received.');
  }

  const json = item.json || {};
  const structure = json.backendStructureObject || JSON.parse(String(json.backendStructure || '{}'));
  if (!Array.isArray(structure.files) || !structure.files.length) {
    throw new Error('Backend structure does not contain any files.');
  }

  function normalizePath(entry, index) {
    const filePath = typeof entry === 'string' ? String(entry).trim() : String(entry?.path || '').trim();
    if (!filePath.startsWith('backend/')) {
      throw new Error(`Invalid backend structure path at index ${index}: ${filePath || '<empty>'}`);
    }
    return filePath;
  }

  function priority(path) {
    const p = String(path || '').toLowerCase();
    if (p === 'backend/pom.xml') return 0;
    if (p.endsWith('/application.java')) return 1;
    if (p.includes('/src/main/resources/application.')) return 2;
    if (p.includes('/src/main/resources/db/changelog/')) return 3;
    if (p.includes('/config/')) return 4;
    if (p.includes('/domain/')) return 5;
    if (p.includes('/repository/')) return 6;
    if (p.includes('/service/')) return 7;
    if (p.includes('/web/rest/')) return 8;
    return 9;
  }

  function buildInitialBatch(sortedFiles, batchSize) {
    const files = Array.isArray(sortedFiles) ? sortedFiles : [];
    if (!files.length) return [];
    const pom = files.find((file) => String(file?.path || '').trim() === 'backend/pom.xml');
    if (pom) return [pom];
    return files.slice(0, batchSize);
  }

  const seen = new Set();
  const files = structure.files
    .map((entry, index) => ({ path: normalizePath(entry, index) }))
    .filter((file) => {
      if (seen.has(file.path)) {
        throw new Error(`Duplicate backend structure path: ${file.path}`);
      }
      seen.add(file.path);
      return true;
    })
    .sort((a, b) => {
      const pa = priority(a.path);
      const pb = priority(b.path);
      if (pa !== pb) return pa - pb;
      return a.path.localeCompare(b.path);
    });

  const batchSize = Math.max(1, Number(json.batchSize || 6));
  const currentBatchFiles = buildInitialBatch(files, batchSize);

  return [{
    json: {
      ...json,
      allPlannedFiles: files,
      remainingFiles: files,
      generatedFiles: [],
      generatedFilePaths: [],
      lastIterationFiles: [],
      totalPlannedFiles: files.length,
      generatedFileCountTotal: 0,
      remainingFileCount: files.length,
      batchSize,
      currentBatchFiles,
      currentBatchFileCount: currentBatchFiles.length,
      iteration: 1,
      hasRemainingFiles: files.length > 0 ? 'yes' : 'no',
    },
    binary: item.binary ?? {},
  }];
}

return beInitGenerationState();

function beBuildChunkPrompt() {
  const MAX_CONTEXT_FILES = 12;
  const MAX_TOTAL_CONTEXT_CHARS = 72000;
  const MAX_FILE_CONTEXT_CHARS = 14000;
  const POM_PATH = 'backend/pom.xml';

  function compactJson(value) {
    return JSON.stringify(value);
  }

  function splitTokens(value) {
    const text = String(value || '')
      .replace(/([a-z0-9])([A-Z])/g, '$1 $2')
      .replace(/[^A-Za-z0-9]+/g, ' ')
      .toLowerCase();
    return Array.from(new Set(text.split(/\s+/).filter((token) => token.length > 1)));
  }

  function role(path) {
    const lower = String(path || '').toLowerCase();
    for (const part of ['domain', 'repository', 'service', 'dto', 'mapper', 'controller', 'config']) {
      if (lower.includes('/' + part + '/') || lower.includes('.' + part + '.')) return part;
    }
    return 'other';
  }

  function dirname(path) {
    const normalized = String(path || '').replace(/\\/g, '/');
    const lastSlash = normalized.lastIndexOf('/');
    return lastSlash === -1 ? '' : normalized.slice(0, lastSlash);
  }

  function basename(path) {
    const normalized = String(path || '').replace(/\\/g, '/');
    const lastSlash = normalized.lastIndexOf('/');
    return lastSlash === -1 ? normalized : normalized.slice(lastSlash + 1);
  }

  function featureKey(path) {
    const name = basename(path).replace(/\.[^.]+$/, '');
    const normalized = String(name || '').replace(
      /(ApplicationTests|Application|Controller|Resource|ServiceImpl|Service|Repository|Mapper|DTO|Entity|IT|Test)$/i,
      '',
    );
    return normalized.toLowerCase();
  }

  function sharedPrefixDepth(pathA, pathB) {
    const a = String(pathA || '').split('/');
    const b = String(pathB || '').split('/');
    let depth = 0;
    while (depth < a.length && depth < b.length && a[depth] === b[depth]) depth += 1;
    return depth;
  }

  function scoreContextFile(file, batchPaths) {
    const filePath = String(file?.path || '').trim();
    const fileTokens = splitTokens(filePath);
    const fileRole = role(filePath);
    const fileDir = dirname(filePath);
    const fileFeature = featureKey(filePath);
    let score = 0;

    for (const batchPath of batchPaths) {
      const batchTokens = splitTokens(batchPath);
      score += batchTokens.filter((t) => fileTokens.includes(t)).length * 2;
      score += sharedPrefixDepth(filePath, batchPath) * 3;
      if (role(batchPath) === fileRole && fileRole !== 'other') score += 5;
      if (dirname(batchPath) === fileDir && fileDir) score += 8;
      if (featureKey(batchPath) && featureKey(batchPath) === fileFeature) score += 12;
    }

    if (filePath === POM_PATH) score += 80;
    if (filePath.includes('/config/')) score += 8;
    return score;
  }

  function pickCurrentImplementation(currentFiles, currentBatchFiles) {
    const batchPaths = currentBatchFiles.map((f) => String(f?.path || '').trim()).filter(Boolean);
    const batchSet = new Set(batchPaths);
    const files = (Array.isArray(currentFiles) ? currentFiles : [])
      .filter((file) => file && typeof file === 'object')
      .map((file) => ({ path: String(file.path || '').trim(), content: String(file.content ?? '') }))
      .filter((file) => file.path && file.path.startsWith('backend/') && !batchSet.has(file.path));

    const byPath = new Map(files.map((file) => [file.path, file]));
    const selected = [];
    const selectedSet = new Set();
    let total = 0;

    function addFile(file) {
      if (!file || !file.path || selectedSet.has(file.path)) return;
      if (selected.length >= MAX_CONTEXT_FILES || total >= MAX_TOTAL_CONTEXT_CHARS) return;
      const remaining = MAX_TOTAL_CONTEXT_CHARS - total;
      if (remaining <= 0) return;
      const take = Math.min(MAX_FILE_CONTEXT_CHARS, remaining);
      const content = String(file.content || '').slice(0, take);
      selected.push({ path: file.path, content });
      selectedSet.add(file.path);
      total += content.length;
    }

    const batchDirs = new Set(batchPaths.map((path) => dirname(path)).filter(Boolean));
    const batchFeatures = new Set(batchPaths.map((path) => featureKey(path)).filter(Boolean));

    if (!batchSet.has(POM_PATH)) {
      addFile(byPath.get(POM_PATH));
    }

    const deterministic = files
      .filter((file) => batchDirs.has(dirname(file.path)) || batchFeatures.has(featureKey(file.path)))
      .sort((a, b) => a.path.localeCompare(b.path));
    for (const file of deterministic) addFile(file);

    const candidates = files
      .map((file) => ({ ...file, score: scoreContextFile(file, batchPaths) }))
      .filter((file) => file.score > 0)
      .sort((a, b) => b.score - a.score || a.path.localeCompare(b.path));
    for (const file of candidates) addFile(file);

    return selected;
  }

  return $input.all().map((item) => {
    const json = item.json || {};
    const requirementsText = String(json.requirementsText || '').trim();
    const openapiText = String(json.openapiText || '').trim();
    if (!requirementsText) throw new Error('Missing requirements text for backend generation.');
    if (!openapiText) throw new Error('Missing OpenAPI text for backend generation.');

    const batchSize = Math.max(1, Number(json.batchSize || 6));
    const currentBatchFiles = Array.isArray(json.currentBatchFiles) && json.currentBatchFiles.length
      ? json.currentBatchFiles.slice(0, batchSize)
      : (Array.isArray(json.remainingFiles) ? json.remainingFiles.slice(0, batchSize) : []);

    if (!currentBatchFiles.length) {
      throw new Error('No current batch files available for backend generation.');
    }

    const allPlannedFiles = Array.isArray(json.allPlannedFiles) && json.allPlannedFiles.length
      ? json.allPlannedFiles
      : currentBatchFiles;
    const allPlannedPaths = allPlannedFiles.map((file) => String(file?.path || '').trim()).filter(Boolean);

    const currentFiles = Array.isArray(json.generatedFiles) ? json.generatedFiles : [];
    const currentImplementation = pickCurrentImplementation(currentFiles, currentBatchFiles);
    const pomContext = currentImplementation.find((file) => file.path === POM_PATH);
    const batchPayload = currentBatchFiles.map((file) => ({ path: String(file?.path || '').trim() })).filter((f) => f.path);

    const userPrompt = [
      'REQ', requirementsText,
      'API', openapiText,
      'PLAN', compactJson(allPlannedPaths),
      'BATCH', compactJson(batchPayload),
      pomContext ? 'POM_CONTEXT' : '',
      pomContext ? pomContext.content : '',
      currentImplementation.length ? 'CURRENT_IMPLEMENTATION' : '',
      currentImplementation.length ? compactJson(currentImplementation) : '',
      'STATE', compactJson({
        iteration: Number(json.iteration || 1),
        generated: Number(json.generatedFileCountTotal || 0),
        remaining: Number(json.remainingFileCount || 0),
        batchSize,
        batchCount: batchPayload.length,
      }),
      'RULES', [
        'Generate only BATCH paths and return all of them in this iteration.',
        'PLAN is the full allowed backend path set.',
        'Do not reference types, classes, packages, or files outside BATCH, CURRENT_IMPLEMENTATION, or PLAN.',
        'OpenAPI is absolute truth for endpoints, methods, schemas, field names, status codes, and security.',
        'For each file, return complete compilable content (no snippets).',
        'Keep package names, imports, and class names consistent with CURRENT_IMPLEMENTATION and PLAN.',
        'When POM_CONTEXT is present, treat it as the source of truth for dependencies and build plugins.',
        'Do not invent build coordinates or dependencies already defined in pom.xml context.',
        'Return only valid JSON with a top-level files array.',
      ].join('\n'),
    ].filter(Boolean).join('\n');

    return {
      json: {
        ...json,
        batchSize,
        allPlannedFiles,
        currentBatchFiles,
        currentBatchFileCount: currentBatchFiles.length,
        currentImplementationCount: currentImplementation.length,
        userPrompt,
        requirementsPromptLength: requirementsText.length,
        openapiPromptLength: openapiText.length,
        currentImplementationLength: compactJson(currentImplementation).length,
        fullPromptLength: userPrompt.length,
      },
      binary: item.binary ?? {},
    };
  });
}

return beBuildChunkPrompt();

function beCleanChunkResponse() {
    function parseCandidate(raw) {
      try {
        const parsed = JSON.parse(raw);
        if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
          return parsed;
        }
      } catch {}
      return null;
    }

    function normalizeText(raw) {
      let text = String(raw ?? '').trim();
      if (!text) {
        throw new Error('Backend chunk model output is empty.');
      }

      if (text.startsWith('```')) {
        const firstNewlineIndex = text.indexOf('\n');
        if (firstNewlineIndex !== -1) {
          const openingFence = text.slice(0, firstNewlineIndex).trim();
          if (/^\`\`\`(?:json)?$/i.test(openingFence)) {
            text = text.slice(firstNewlineIndex + 1);
            const trailingFenceIndex = text.lastIndexOf('\n\`\`\`');
            if (trailingFenceIndex !== -1 && text.slice(trailingFenceIndex).trim() === '```') {
              text = text.slice(0, trailingFenceIndex).trim();
            } else if (text.endsWith('```')) {
              text = text.slice(0, -3).trim();
            } else {
              text = text.trim();
            }
          }
        }
      }

      return text;
    }

    function extractBalancedObject(text) {
      let depth = 0;
      let start = -1;
      let inString = false;
      let escaped = false;

      for (let index = 0; index < text.length; index += 1) {
        const char = text[index];

        if (escaped) {
          escaped = false;
          continue;
        }

        if (char === '\\') {
          if (inString) escaped = true;
          continue;
        }

        if (char === '"') {
          inString = !inString;
          continue;
        }

        if (inString) continue;

        if (char === '{') {
          if (depth === 0) start = index;
          depth += 1;
          continue;
        }

        if (char === '}') {
          if (depth > 0) {
            depth -= 1;
            if (depth === 0 && start !== -1) {
              return text.slice(start, index + 1);
            }
          }
        }
      }

      return null;
    }

    function isQuoteEscaped(text, quoteIndex) {
      let backslashCount = 0;
      for (let index = quoteIndex - 1; index >= 0 && text[index] === '\\'; index -= 1) {
        backslashCount += 1;
      }
      return backslashCount % 2 === 1;
    }

    function findPropertyKey(text, key, fromIndex) {
      const pattern = '"' + key + '"';
      return text.indexOf(pattern, fromIndex);
    }

    function findValueStart(text, keyIndex) {
      const colonIndex = text.indexOf(':', keyIndex);
      if (colonIndex === -1) return -1;
      for (let index = colonIndex + 1; index < text.length; index += 1) {
        if (/\s/.test(text[index])) continue;
        return index;
      }
      return -1;
    }

    function decodeLooseJsonString(raw) {
      let output = '';

      for (let index = 0; index < raw.length; index += 1) {
        const char = raw[index];
        if (char !== '\\') {
          output += char;
          continue;
        }

        const next = raw[index + 1];
        if (next === undefined) {
          output += '\\';
          break;
        }

        if (next === 'n') {
          output += '\n';
          index += 1;
          continue;
        }
        if (next === 'r') {
          output += '\r';
          index += 1;
          continue;
        }
        if (next === 't') {
          output += '\t';
          index += 1;
          continue;
        }
        if (next === 'b') {
          output += '\b';
          index += 1;
          continue;
        }
        if (next === 'f') {
          output += '\f';
          index += 1;
          continue;
        }
        if (next === '"' || next === '\\' || next === '/') {
          output += next;
          index += 1;
          continue;
        }
        if (next === 'u' && /^[0-9a-fA-F]{4}$/.test(raw.slice(index + 2, index + 6))) {
          output += String.fromCharCode(parseInt(raw.slice(index + 2, index + 6), 16));
          index += 5;
          continue;
        }

        output += '\\' + next;
        index += 1;
      }

      return output;
    }

    function readStrictQuotedString(text, quoteStart) {
      for (let index = quoteStart + 1; index < text.length; index += 1) {
        if (text[index] === '"' && !isQuoteEscaped(text, index)) {
          return {
            value: decodeLooseJsonString(text.slice(quoteStart + 1, index)),
            endIndex: index,
          };
        }
      }
      throw new Error('Could not find closing quote for JSON string.');
    }

    function readStructuredJsonValue(text, valueStart) {
      const openingChar = text[valueStart];
      const closingChar = openingChar === '{' ? '}' : ']';
      const stack = [closingChar];
      let inString = false;
      let escaped = false;

      for (let index = valueStart + 1; index < text.length; index += 1) {
        const char = text[index];

        if (escaped) {
          escaped = false;
          continue;
        }

        if (char === '\\') {
          if (inString) escaped = true;
          continue;
        }

        if (char === '"') {
          inString = !inString;
          continue;
        }

        if (inString) continue;

        if (char === '{') {
          stack.push('}');
          continue;
        }
        if (char === '[') {
          stack.push(']');
          continue;
        }

        if (char === stack[stack.length - 1]) {
          stack.pop();
          if (!stack.length) {
            const rawValue = text.slice(valueStart, index + 1);
            return {
              value: JSON.parse(rawValue),
              endIndex: index,
            };
          }
        }
      }

      throw new Error('Could not find the end of generated file content JSON value.');
    }

    function readPrimitiveJsonValue(text, valueStart) {
      let endIndex = valueStart;
      while (endIndex < text.length && !/[\s,\}\]]/.test(text[endIndex])) {
        endIndex += 1;
      }

      const rawValue = text.slice(valueStart, endIndex).trim();
      if (!rawValue) {
        throw new Error('Generated file content JSON value is empty.');
      }

      return {
        value: JSON.parse(rawValue),
        endIndex: endIndex - 1,
      };
    }

    function readLooseJsonValue(text, valueStart) {
      if (valueStart < 0 || valueStart >= text.length) {
        throw new Error('Could not find content value in generated file object.');
      }

      const firstChar = text[valueStart];
      if (firstChar === '"') {
        return readStrictQuotedString(text, valueStart);
      }
      if (firstChar === '{' || firstChar === '[') {
        return readStructuredJsonValue(text, valueStart);
      }

      return readPrimitiveJsonValue(text, valueStart);
    }

    function canRecoverTruncatedTextFile(filePath) {
      const lower = String(filePath || '').toLowerCase();
      return lower.endsWith('.md') || lower.endsWith('.txt');
    }

    function decodeLooseJsonTail(raw) {
      let tail = String(raw || '');
      if (tail.endsWith('```')) {
        tail = tail.slice(0, -3);
      }
      return decodeLooseJsonString(tail).trimEnd();
    }

    function isLikelyIncompletePayloadError(error) {
      const message = String(error?.message ?? error ?? '');
      return (
        message.includes('Could not find closing quote') ||
        message.includes('Could not find the end of generated file content JSON value') ||
        message.includes('did not end after content field') ||
        message.includes('files array was not closed') ||
        message.includes('ended before files array closed') ||
        message.includes('Could not find content value')
      );
    }

    function parseLooseFilesPayload(text, allowPartial = false) {
      const filesKeyIndex = findPropertyKey(text, 'files', 0);
      if (filesKeyIndex === -1) {
        throw new Error('Chunk payload does not contain a files property.');
      }

      const arrayStart = text.indexOf('[', filesKeyIndex);
      if (arrayStart === -1) {
