    if (action !== 'remove') {
      const rawDescription = String(entry.description ?? entry.summary ?? entry.reason ?? '').trim();
      normalizedEntry.description = rawDescription || (action === 'create'
        ? 'Create this file for the requested refinement.'
        : 'Modify this file for the requested refinement.');
    }
    refinementPlanFiles.push(normalizedEntry);
  }
  const backendRoot = String(json.backendRoot ?? 'backend').trim() || 'backend';
  const backendFiles = await collectCurrentBackendFiles.call(this, binary, backendRoot);
  if (!backendFiles.length) {
    throw new Error('Current backend ZIP could not be unpacked into files for refinement.');
  }
  const backendFileMap = new Map(backendFiles.map((file) => [file.path, file]));
  const structureTextCandidates = [
    String(json.backendStructure ?? '').trim(),
    String(json.structurePlan ?? '').trim(),
    decodeBinaryText(binary.backendStructure),
  ].filter(Boolean);
  const parsedStructure = structureTextCandidates.map(parseStructure).find(Boolean);
  const currentPlanFiles = uniquePaths(parsedStructure?.files?.length ? parsedStructure.files : backendFiles.map((file) => ({ path: file.path })));

  const removePaths = new Set(refinementPlanFiles.filter((file) => file.action === 'remove').map((file) => file.path));
  const workItems = prioritizeRefinementItems(refinementPlanFiles
    .filter((file) => file.action !== 'remove')
    .map((file) => ({
      path: file.path,
      action: file.action,
      description: file.action === 'remove' ? undefined : String(file.description || '').trim(),
      currentExists: backendFileMap.has(file.path),
    })));

  const currentBackendFiles = backendFiles.filter((file) => !removePaths.has(file.path));
  const currentPlanPaths = currentPlanFiles.filter((file) => !removePaths.has(file.path));
  for (const workItem of workItems) {
    if (!currentPlanPaths.some((file) => file.path === workItem.path)) currentPlanPaths.push({ path: workItem.path });
  }

  const batchSize = Math.max(1, Number(json.refinementBatchSize ?? 6));
  const currentBatchFiles = buildRefinementBatch(workItems, batchSize);
  const backendStructureObject = { files: currentPlanPaths };
  const backendStructure = JSON.stringify(backendStructureObject);

  return [{
    json: {
      ...json,
      refinementPlanFiles,
      removeFilePaths: Array.from(removePaths),
      generatedFiles: currentBackendFiles,
      generatedFilePaths: currentBackendFiles.map((file) => file.path),
      generatedFileCountTotal: currentBackendFiles.length,
      currentPlanFiles: currentPlanPaths,
      plannedFiles: currentPlanPaths,
      backendStructure,
      backendStructureObject,
      remainingFiles: workItems,
      remainingFileCount: workItems.length,
      currentBatchFiles,
      currentBatchFileCount: currentBatchFiles.length,
      allPlannedFiles: currentPlanPaths,
      allowedOutputFiles: currentBatchFiles.map((file) => ({ path: file.path })),
      lastIterationFiles: [],
      recentImplementationSummaries: [],
      generatedImplementationIndex: [],
      batchSize,
      iteration: 1,
      hasRemainingFiles: workItems.length > 0 ? 'yes' : 'no',
    },
    binary,
  }];
}

return beInitRefinementState();

function beBuildRefinementChunkPrompt() {
  const MAX_MEMORY_ITEMS = 10;
  const ATTACHMENT_CHAR_LIMIT = 12000;
  const ATTACHMENT_FILE_CHAR_LIMIT = 3000;
  const MAX_RELATED_FILES = 4;
  const MAX_RELATED_FILE_CHARS = 7000;
  const POM_PATH = 'backend/pom.xml';

  function compactJson(value) { return JSON.stringify(value); }

  function normalizeFiles(value) {
    const files = Array.isArray(value) ? value : [];
    return files.map((entry) => {
      if (typeof entry === 'string') return { path: entry.trim() };
      if (entry && typeof entry === 'object') return { path: String(entry.path ?? '').trim() };
      return { path: '' };
    }).filter((entry) => entry.path);
  }

  function decodeText(binaryEntry) {
    try {
      const raw = String(binaryEntry?.data ?? '');
      return raw ? Buffer.from(raw, 'base64').toString('utf8') : '';
    } catch {
      return '';
    }
  }

  function normalizeBackendPath(rawPath, backendRoot, rawDirectory) {
    const normalizedRoot = String(backendRoot || 'backend').replace(/\\/g, '/').trim().replace(/\/+$/, '') || 'backend';
    const directory = String(rawDirectory ?? '').replace(/\\/g, '/').trim().replace(/^\.\//, '').replace(/\/+$/, '');
    const fileName = String(rawPath ?? '').replace(/\\/g, '/').trim().replace(/^\.\//, '');
    const combined = [directory, fileName]
      .filter(Boolean)
      .join('/')
      .replace(/\/+/g, '/')
      .replace(/^\.\//, '')
      .replace(/\/+/g, '/');
    if (!combined) return '';
    if (combined === normalizedRoot || combined === normalizedRoot + '.zip') return '';
    if (combined.startsWith(normalizedRoot + '/')) return combined;
    return normalizedRoot + '/' + combined.replace(/^\/+/, '');
  }

  function looksTextLike(binaryEntry, key) {
    const mime = String(binaryEntry?.mimeType ?? '').toLowerCase();
    const extRaw = String(binaryEntry?.fileExtension ?? '').toLowerCase();
    const ext = extRaw.startsWith('.') ? extRaw.slice(1) : extRaw;
    const textExt = new Set(['txt','md','markdown','json','yaml','yml','csv','tsv','xml','html','htm','js','ts','py','java','sql','log','ini','cfg']);
    if (mime.startsWith('text/')) return true;
    if (mime.includes('json') || mime.includes('xml') || mime.includes('yaml')) return true;
    if (textExt.has(ext)) return true;
    const keyLower = String(key ?? '').toLowerCase();
    return keyLower.endsWith('.txt') || keyLower.endsWith('.md') || keyLower.endsWith('.json');
  }

  function splitTokens(value) {
    const text = String(value || '').replace(/([a-z0-9])([A-Z])/g, '$1 $2').replace(/[^A-Za-z0-9]+/g, ' ').toLowerCase();
    return Array.from(new Set(text.split(/\s+/).filter((token) => token.length > 1)));
  }

  function detectLanguage(filePath) {
    const lower = String(filePath || '').toLowerCase();
    if (lower.endsWith('.java')) return 'java';
    if (lower.endsWith('.kt')) return 'kotlin';
    if (lower.endsWith('.py')) return 'python';
    if (lower.endsWith('.ts')) return 'typescript';
    if (lower.endsWith('.tsx')) return 'tsx';
    if (lower.endsWith('.js')) return 'javascript';
    if (lower.endsWith('.jsx')) return 'jsx';
    if (lower.endsWith('.cs')) return 'csharp';
    if (lower.endsWith('.go')) return 'go';
    if (lower.endsWith('.rb')) return 'ruby';
    if (lower.endsWith('.php')) return 'php';
    return 'other';
  }

  function isImplementationFile(filePath) {
    const lower = String(filePath || '').toLowerCase();
    if (!lower.startsWith('backend/')) return false;
    if (lower.includes('/src/test/') || lower.includes('/tests/') || lower.includes('/test/')) return false;
    if (lower.includes('/resources/') || lower.includes('/db/') || lower.includes('/docs/') || lower.includes('/helm/')) return false;
    if (lower.endsWith('.md') || lower.endsWith('.txt') || lower.endsWith('.yaml') || lower.endsWith('.yml') || lower.endsWith('.xml') || lower.endsWith('.properties') || lower.endsWith('.sql') || lower.endsWith('.json') || lower.endsWith('.csv')) return false;
    return new Set(['java', 'kotlin', 'python', 'typescript', 'tsx', 'javascript', 'jsx', 'csharp', 'go', 'ruby', 'php']).has(detectLanguage(filePath));
  }

  function summarizeFile(file) {
    const filePath = String(file?.path || '').trim();
    const content = String(file?.content || '');
    const language = detectLanguage(filePath);
    const imports = [];
    for (const regex of [/^[ \t]*import\s+([^;\n]+)[;\n]?/gm, /^[ \t]*using\s+([^;\n]+);/gm, /^[ \t]*from\s+([^\n]+)\s+import\s+([^\n]+)/gm, /^[ \t]*require\(['"]([^'"]+)['"]\)/gm]) {
      let match;
      while ((match = regex.exec(content)) !== null && imports.length < 20) imports.push(match.slice(1).filter(Boolean).join(' ').trim());
      regex.lastIndex = 0;
    }
    const types = [];
    let match;
    const typeRegex = /^[ \t]*(?:export\s+)?(?:public\s+|private\s+|protected\s+|internal\s+)?(?:abstract\s+|final\s+|sealed\s+)?(class|interface|enum|record|type|struct)\s+([A-Za-z0-9_]+)/gm;
    while ((match = typeRegex.exec(content)) !== null && types.length < 12) types.push({ kind: match[1], name: match[2] });
    typeRegex.lastIndex = 0;
    const functions = [];
    const fnRegex = /^[ \t]*(?:export\s+)?(?:async\s+)?(?:function|def|func|fn)\s+([A-Za-z0-9_]+)\s*\(([^\)]*)\)/gm;
    while ((match = fnRegex.exec(content)) !== null && functions.length < 20) functions.push({ name: match[1], parameters: String(match[2] || '').trim() });
    fnRegex.lastIndex = 0;
    return { path: filePath, language, imports: Array.from(new Set(imports)).slice(0, 20), types, functions, lineCount: content ? content.replace(/\r\n/g, '\n').split('\n').length : 0 };
  }

  function getRole(path) {
    const lower = String(path || '').toLowerCase();
    for (const role of ['controller', 'service', 'repository', 'dto', 'mapper', 'entity', 'config', 'security']) {
      if (lower.includes(role)) return role;
    }
    return 'other';
  }

  function sharedPrefixDepth(pathA, pathB) {
    const a = String(pathA || '').split('/');
    const b = String(pathB || '').split('/');
    let depth = 0;
    while (depth < a.length && depth < b.length && a[depth] === b[depth]) depth += 1;
    return depth;
  }

  function scoreSummary(summary, batchItems) {
    const summaryTokens = splitTokens(summary.path + ' ' + JSON.stringify(summary.types || []) + ' ' + JSON.stringify(summary.functions || []));
    const summaryRole = getRole(summary.path);
    let score = 0;
    for (const batchItem of batchItems) {
      const batchPath = String(batchItem.path || '').trim();
      const overlap = splitTokens(batchPath).filter((token) => summaryTokens.includes(token)).length;
      score += overlap * 2 + sharedPrefixDepth(summary.path, batchPath) * 3;
      if (getRole(batchPath) === summaryRole && summaryRole !== 'other') score += 4;
    }
    return score;
  }

  function selectRelevantMemory(currentFiles, batchItems) {
    const batchPaths = new Set(batchItems.map((item) => String(item.path || '').trim()));
    return currentFiles
      .filter((file) => isImplementationFile(file.path))
      .filter((file) => !batchPaths.has(String(file.path || '').trim()))
      .map(summarizeFile)
      .map((summary) => ({ summary, score: scoreSummary(summary, batchItems) }))
      .filter((entry) => entry.score > 0)
      .sort((a, b) => b.score - a.score || a.summary.path.localeCompare(b.summary.path))
      .slice(0, MAX_MEMORY_ITEMS)
      .map((entry) => entry.summary);
  }

  function selectRelatedImplementation(currentFiles, batchItems) {
    const batchPaths = new Set(batchItems.map((item) => String(item.path || '').trim()));
    return currentFiles
      .filter((file) => isImplementationFile(file.path))
      .filter((file) => !batchPaths.has(String(file.path || '').trim()))
      .map((file) => ({ file, score: scoreSummary(summarizeFile(file), batchItems) }))
      .filter((entry) => entry.score > 0)
      .sort((a, b) => b.score - a.score || String(a.file.path).localeCompare(String(b.file.path)))
      .slice(0, MAX_RELATED_FILES)
      .map((entry) => ({
        path: String(entry.file.path || '').trim(),
        content: String(entry.file.content ?? '').slice(0, MAX_RELATED_FILE_CHARS),
      }));
  }

  return $input.all().map((item) => {
    const json = item.json || {};
    const binary = item.binary || {};
    const reviewerFeedback = String(json.reviewerFeedback || json.feedback || json.Feedback || '').trim() || 'Reviewer requested backend changes without additional details.';
    const batchSize = Math.max(1, Number(json.batchSize || 6));
    const currentBatchFiles = Array.isArray(json.currentBatchFiles) && json.currentBatchFiles.length ? json.currentBatchFiles.slice(0, batchSize) : (Array.isArray(json.remainingFiles) ? json.remainingFiles.slice(0, batchSize) : []);
    if (!currentBatchFiles.length) throw new Error('No current refinement batch files available for backend refinement.');

    const backendRoot = String(json.backendRoot || 'backend').trim() || 'backend';
    const currentFiles = Array.isArray(json.generatedFiles) ? json.generatedFiles : [];
    const currentFileMap = new Map(
      currentFiles
        .map((file) => [String(file.path || '').trim().replace(/\\/g, '/'), String(file.content ?? '')])
        .filter(([path]) => path),
    );
    const binaryCurrentFileMap = new Map(
      Object.entries(binary)
        .filter(([name]) => /^current_/i.test(String(name)))
        .map(([, entry]) => {
          const path = normalizeBackendPath(entry?.fileName, backendRoot, entry?.directory);
          return [path, decodeText(entry)];
        })
        .filter(([path]) => path),
    );

    const batchPayload = currentBatchFiles.map((entry) => {
      const path = String(entry.path || '').trim().replace(/\\/g, '/');
      const action = String(entry.action || 'modify').trim().toLowerCase();
      const description = String(entry.description || '').trim();
      const payload = { path, action };
      if (action !== 'remove') {
        payload.description = description || (action === 'create'
          ? 'Create this file for the requested refinement.'
          : 'Modify this file for the requested refinement.');
      }
      if (action === 'modify') {
        if (currentFileMap.has(path)) payload.currentContent = currentFileMap.get(path);
        else if (binaryCurrentFileMap.has(path)) payload.currentContent = binaryCurrentFileMap.get(path);
      }
      return payload;
    });

    const currentImplementation = batchPayload
      .filter((entry) => entry.action === 'modify')
      .map((entry) => ({ path: entry.path, currentContent: String(entry.currentContent ?? '') }));

    const pomContext = currentFileMap.get(POM_PATH) || binaryCurrentFileMap.get(POM_PATH) || '';

    const attachmentBlocks = [];
    let totalChars = 0;
    for (const [key, entry] of Object.entries(binary).filter(([name]) => /^attachments?(?:_|$)/i.test(String(name)))) {
      if (totalChars >= ATTACHMENT_CHAR_LIMIT || !looksTextLike(entry, key)) continue;
      const text = decodeText(entry).trim();
      if (!text) continue;
      const take = Math.min(ATTACHMENT_FILE_CHAR_LIMIT, ATTACHMENT_CHAR_LIMIT - totalChars);
      attachmentBlocks.push(`Attachment: ${String(entry.fileName || key)}\n---\n${text.slice(0, take)}`);
      totalChars += Math.min(text.length, take);
    }

    const memory = selectRelevantMemory(currentFiles, currentBatchFiles);
    const relatedImplementation = selectRelatedImplementation(currentFiles, currentBatchFiles);
    const currentPlanPaths = normalizeFiles(json.currentPlanFiles).map((file) => file.path);

    const userPrompt = [
      'FEEDBACK', reviewerFeedback,
      attachmentBlocks.length ? 'ATTACHMENTS\n' + attachmentBlocks.join('\n\n') : '',
      'CURRENT_PLAN', compactJson(currentPlanPaths),
      'BATCH', compactJson(batchPayload),
      pomContext ? 'POM_CONTEXT' : '',
      pomContext ? String(pomContext) : '',
      currentImplementation.length ? 'CURRENT_IMPLEMENTATION' : '',
      currentImplementation.length ? compactJson(currentImplementation) : '',
      relatedImplementation.length ? 'RELATED_IMPLEMENTATION\n' + compactJson(relatedImplementation) : '',
      memory.length ? 'MEMORY\n' + compactJson(memory) : '',
      'RULES', [
        'Generate only the files listed in BATCH with action create or modify, using each description as intent.',
        'Do not output files whose action is remove.',
        'For modify actions, use CURRENT_IMPLEMENTATION as the baseline and return the complete updated file content.',
        'For create actions, return the complete new file content.',
        'When POM_CONTEXT is present, treat it as the source of truth for dependencies and build plugins.',
        'Keep changes tightly aligned with FEEDBACK and ATTACHMENTS.',
        'Preserve backend consistency with the existing package.',
        'Return only valid JSON with a top-level files array.',
      ].join('\\n'),
    ].filter(Boolean).join('\n');

    return {
      json: {
        ...json,
        currentBatchFiles,
        currentBatchFileCount: currentBatchFiles.length,
        allPlannedFiles: currentPlanPaths.map((path) => ({ path })),
        allowedOutputFiles: currentBatchFiles.map((entry) => ({ path: String(entry.path || '').trim() })),
        userPrompt,
        fullPromptLength: userPrompt.length,
        refinementMemoryLength: compactJson(memory).length,
      },
      binary,
    };
  });
}

return beBuildRefinementChunkPrompt();

function beCleanChunkResponse() {
    function parseCandidate(raw) {
      try {
        const parsed = JSON.parse(raw);
        if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
          return parsed;
        }
      } catch {}
      return null;
    }

    function normalizeText(raw) {
      let text = String(raw ?? '').trim();
      if (!text) {
        throw new Error('Backend chunk model output is empty.');
      }

      if (text.startsWith('```')) {
        const firstNewlineIndex = text.indexOf('\n');
        if (firstNewlineIndex !== -1) {
          const openingFence = text.slice(0, firstNewlineIndex).trim();
          if (/^\`\`\`(?:json)?$/i.test(openingFence)) {
            text = text.slice(firstNewlineIndex + 1);
            const trailingFenceIndex = text.lastIndexOf('\n\`\`\`');
            if (trailingFenceIndex !== -1 && text.slice(trailingFenceIndex).trim() === '```') {
              text = text.slice(0, trailingFenceIndex).trim();
            } else if (text.endsWith('```')) {
              text = text.slice(0, -3).trim();
            } else {
              text = text.trim();
            }
          }
        }
      }

      return text;
    }

    function extractBalancedObject(text) {
      let depth = 0;
      let start = -1;
      let inString = false;
      let escaped = false;

      for (let index = 0; index < text.length; index += 1) {
        const char = text[index];

        if (escaped) {
          escaped = false;
          continue;
        }

        if (char === '\\') {
          if (inString) escaped = true;
          continue;
        }

        if (char === '"') {
          inString = !inString;
          continue;
        }

        if (inString) continue;

        if (char === '{') {
          if (depth === 0) start = index;
          depth += 1;
          continue;
        }

        if (char === '}') {
          if (depth > 0) {
            depth -= 1;
            if (depth === 0 && start !== -1) {
              return text.slice(start, index + 1);
            }
          }
        }
      }

      return null;
    }

    function isQuoteEscaped(text, quoteIndex) {
      let backslashCount = 0;
      for (let index = quoteIndex - 1; index >= 0 && text[index] === '\\'; index -= 1) {
        backslashCount += 1;
      }
      return backslashCount % 2 === 1;
    }

    function findPropertyKey(text, key, fromIndex) {
      const pattern = '"' + key + '"';
      return text.indexOf(pattern, fromIndex);
    }

    function findValueStart(text, keyIndex) {
      const colonIndex = text.indexOf(':', keyIndex);
      if (colonIndex === -1) return -1;
      for (let index = colonIndex + 1; index < text.length; index += 1) {
        if (/\s/.test(text[index])) continue;
        return index;
      }
      return -1;
    }

    function decodeLooseJsonString(raw) {
      let output = '';

      for (let index = 0; index < raw.length; index += 1) {
        const char = raw[index];
        if (char !== '\\') {
          output += char;
          continue;
        }

        const next = raw[index + 1];
        if (next === undefined) {
          output += '\\';
          break;
        }

        if (next === 'n') {
          output += '\n';
          index += 1;
          continue;
        }
        if (next === 'r') {
          output += '\r';
          index += 1;
          continue;
        }
        if (next === 't') {
          output += '\t';
          index += 1;
          continue;
        }
        if (next === 'b') {
          output += '\b';
          index += 1;
          continue;
        }
        if (next === 'f') {
          output += '\f';
          index += 1;
          continue;
        }
        if (next === '"' || next === '\\' || next === '/') {
          output += next;
          index += 1;
          continue;
        }
        if (next === 'u' && /^[0-9a-fA-F]{4}$/.test(raw.slice(index + 2, index + 6))) {
          output += String.fromCharCode(parseInt(raw.slice(index + 2, index + 6), 16));
          index += 5;
          continue;
        }

        output += '\\' + next;
        index += 1;
      }

      return output;
    }

    function readStrictQuotedString(text, quoteStart) {
      for (let index = quoteStart + 1; index < text.length; index += 1) {
        if (text[index] === '"' && !isQuoteEscaped(text, index)) {
          return {
            value: decodeLooseJsonString(text.slice(quoteStart + 1, index)),
            endIndex: index,
          };
        }
      }
      throw new Error('Could not find closing quote for JSON string.');
    }

    function readStructuredJsonValue(text, valueStart) {
      const openingChar = text[valueStart];
      const closingChar = openingChar === '{' ? '}' : ']';
      const stack = [closingChar];
      let inString = false;
      let escaped = false;

      for (let index = valueStart + 1; index < text.length; index += 1) {
        const char = text[index];

        if (escaped) {
          escaped = false;
          continue;
        }

        if (char === '\\') {
          if (inString) escaped = true;
          continue;
        }

        if (char === '"') {
          inString = !inString;
          continue;
        }

        if (inString) continue;

        if (char === '{') {
          stack.push('}');
          continue;
        }
        if (char === '[') {
          stack.push(']');
          continue;
        }

        if (char === stack[stack.length - 1]) {
          stack.pop();
          if (!stack.length) {
            const rawValue = text.slice(valueStart, index + 1);
            return {
              value: JSON.parse(rawValue),
              endIndex: index,
            };
          }
        }
      }

      throw new Error('Could not find the end of generated file content JSON value.');
    }

    function readPrimitiveJsonValue(text, valueStart) {
      let endIndex = valueStart;
      while (endIndex < text.length && !/[\s,\}\]]/.test(text[endIndex])) {
        endIndex += 1;
      }

      const rawValue = text.slice(valueStart, endIndex).trim();
      if (!rawValue) {
        throw new Error('Generated file content JSON value is empty.');
      }

      return {
        value: JSON.parse(rawValue),
        endIndex: endIndex - 1,
      };
    }

    function readLooseJsonValue(text, valueStart) {
      if (valueStart < 0 || valueStart >= text.length) {
        throw new Error('Could not find content value in generated file object.');
      }

      const firstChar = text[valueStart];
      if (firstChar === '"') {
        return readStrictQuotedString(text, valueStart);
      }
      if (firstChar === '{' || firstChar === '[') {
        return readStructuredJsonValue(text, valueStart);
      }

      return readPrimitiveJsonValue(text, valueStart);
    }

    function canRecoverTruncatedTextFile(filePath) {
      const lower = String(filePath || '').toLowerCase();
      return lower.endsWith('.md') || lower.endsWith('.txt');
    }

    function decodeLooseJsonTail(raw) {
      let tail = String(raw || '');
      if (tail.endsWith('```')) {
        tail = tail.slice(0, -3);
      }
      return decodeLooseJsonString(tail).trimEnd();
    }

    function isLikelyIncompletePayloadError(error) {
      const message = String(error?.message ?? error ?? '');
      return (
        message.includes('Could not find closing quote') ||
        message.includes('Could not find the end of generated file content JSON value') ||
        message.includes('did not end after content field') ||
        message.includes('files array was not closed') ||
        message.includes('ended before files array closed') ||
        message.includes('Could not find content value')
      );
    }

    function parseLooseFilesPayload(text, allowPartial = false) {
      const filesKeyIndex = findPropertyKey(text, 'files', 0);
      if (filesKeyIndex === -1) {
        throw new Error('Chunk payload does not contain a files property.');
      }

      const arrayStart = text.indexOf('[', filesKeyIndex);
      if (arrayStart === -1) {
        throw new Error('Chunk payload files property does not contain an array.');
      }

      const files = [];
      let cursor = arrayStart + 1;

      while (cursor < text.length) {
        while (cursor < text.length && /[\s,]/.test(text[cursor])) cursor += 1;
        if (cursor >= text.length) {
          if (allowPartial) {
            return {
              files,
              recoveredPartialChunkPayload: true,
              ignoredIncompleteTrailingFile: true,
              recoveryReason: files.length
                ? 'Chunk payload ended before files array closed.'
                : 'Ignored incomplete trailing generated file because the model output ended before the payload closed.',
            };
          }
          break;
        }
        if (text[cursor] === ']') {
          return { files };
        }
        if (text[cursor] !== '{') {
          cursor += 1;
          continue;
        }

        let pathInfo = null;
        let contentValueStart = -1;

        try {
          const objectStart = cursor;
          const pathKeyIndex = findPropertyKey(text, 'path', objectStart);
          if (pathKeyIndex === -1) {
            throw new Error('Could not find path property in generated file object.');
          }
